function hideAllElements() {
  var elementsToHide = document.querySelectorAll(
    ".form-input-group.start-date, " +
    ".form-input-group.weekly-rate, " +
    ".form-input-group.number-of-weeks, " +
    ".form-input-group.monthly-rate, " +
    ".form-input-group.number-of-months, " +
    ".form-input-group.estimated-hours, " +
    ".form-input-group.frequency, " +
    ".form-input-group.hourly-rate, " +
    ".form-input-group.end-date, " +
    ".form-input-group.maximum-total-hours, " +
    ".form-input-group.estimated-end-date, " +
    ".form-input-group.total-cost, " +
    ".form-input-group.paid-upfront, " +
    ".contract-checkbox.hourly-rate-checkbox, " +
    ".form-contract-label.text-style-italic.condition"
  );
  // fee structure validation
  elementsToHide.forEach(function (element) {
    element.style.display = "none";
    //---------------------------------------------
    var inputFields = element.querySelectorAll("input, select, checkbox");
    inputFields.forEach(function (input) {
      if (input.tagName === "INPUT" || input.tagName === "SELECT") {
        // Handle different types of input fields
        input.value =
          ""; // Clear the value for text, textarea, date, and number inputs
        // input.checked = false; // Uncheck the checkbox
        input.selectedIndex = 0;
        document.getElementById("Ongoing-Hourly-Agreement").checked = false;
      }
    });

    //-----------------------------------------------
  });
}

