const contractRadioBox = document.querySelectorAll(
  ".contract-form-input-radio"
);
const conditionCheckbox = document.querySelector(
  ".contract-form-input-checkbox.condition"
);
var step4 = document.querySelector(".form-progress-contract");
contractRadioBox.forEach((radio) => {
  radio.addEventListener("change", function () {
    const contractSelect = radio.querySelector("input");
    if (contractSelect.checked) {
      if (contractSelect.value === "Your contract") {
        conditionCheckbox.style.display = "flex"; // Show label
        step4.classList.remove("is-done");
        conditionCheckbox.addEventListener("change", function () {
          const checkBox = this.querySelector("input");
          if (checkBox.checked) {
            step4.classList.add("is-done");
          } else {
            step4.classList.remove("is-done");
          }
        });
      } else {
        conditionCheckbox.querySelector("input").checked = false;
        conditionCheckbox
          .querySelector(".w-checkbox-input")
          .classList.remove("w--redirected-checked");
        conditionCheckbox.style.display = "none";
        step4.classList.add("is-done");
      }
    }
  });
});

// form progress - basic info

function formProgressBasicInfo() {
  // init basic information inputs
  var projectNameInput = document.querySelector(
    ".form-contract-input.project-name"
  );
  var hiringManagerNameInput = document.querySelector(
    ".form-contract-input.hiring-manager-name"
  );
  var companyNameInput = document.querySelector(
    ".form-contract-input.company-name"
  );
  var emailAddressInput = document.querySelector(
    ".form-contract-input.email-address"
  );
  var serviceInput = document.querySelector(".form-contract-input.service");

  // init payment and timeline
  var feeStructureSelectInput = document.getElementById("fee-structure");

  var startDateInput = document.querySelector(
    ".form-contract-input.start-date"
  );
  var estimatedEndDateInput = document.querySelector(
    ".form-contract-input.estimated-end-date"
  );
  var totalCostInput = document.querySelector(
    ".form-contract-input.total-cost"
  );
  var paidUpfrontInput = document.querySelector(
    ".form-contract-input.paid-upfront"
  );
  var endDateInput = document.querySelector(".form-contract-input.end-date");

  var hourlyRateInput = document.querySelector(
    ".form-contract-input.hourly-rate"
  );
  var maximumTotalHoursInput = document.querySelector(
    ".form-contract-input.maximum-total-hours"
  );
  var estimatedHoursInput = document.querySelector(
    ".form-contract-input.estimated-hours"
  );
  var frequencyInput = document.querySelector(".form-contract-input.frequency");

  //checkBox Agreement
  var ongoingCheckboxInput = document.querySelector(
    "#Ongoing-Hourly-Agreement"
  );

  var monthlyRateInput = document.querySelector(
    ".form-contract-input.monthly-rate"
  );
  var numberOfMonthsInput = document.querySelector(
    ".form-contract-input.number-of-months"
  );
  var weeklyRateInput = document.querySelector(
    ".form-contract-input.weekly-rate"
  );
  var numberOfWeeksInput = document.querySelector(
    ".form-contract-input.number-of-weeks"
  );
  var messageInput = document.querySelector(".form-contract-input.message");

  // STEPS
  var step1 = document.querySelector(".form-progress-basic");
  var step2 = document.querySelector(".form-progress-payment-timeline");
  var step3 = document.querySelector(".form-progress-project-scope");

  //event listener
  projectNameInput.addEventListener("change", validateForm);
  hiringManagerNameInput.addEventListener("change", validateForm);
  companyNameInput.addEventListener("change", validateForm);
  emailAddressInput.addEventListener("change", validateForm);
  serviceInput.addEventListener("change", validateForm);
  ongoingCheckboxInput.addEventListener("click", validateForm);
  startDateInput.addEventListener("change", validateForm);
  estimatedEndDateInput.addEventListener("change", validateForm);
  totalCostInput.addEventListener("change", validateForm);
  paidUpfrontInput.addEventListener("change", validateForm);
  hourlyRateInput.addEventListener("change", validateForm);
  maximumTotalHoursInput.addEventListener("change", validateForm);
  endDateInput.addEventListener("change", validateForm);
  frequencyInput.addEventListener("change", validateForm);
  monthlyRateInput.addEventListener("change", validateForm);
  numberOfMonthsInput.addEventListener("change", validateForm);
  weeklyRateInput.addEventListener("change", validateForm);
  numberOfWeeksInput.addEventListener("change", validateForm);
  messageInput.addEventListener("change", validateForm);

  function validateForm() {
    //basic information validation

    var projectName = projectNameInput.value;
    var hiringManagerName = hiringManagerNameInput.value;
    var companyName = companyNameInput.value;
    var emailAddress = emailAddressInput.value;
    var service = serviceInput.value;
    // payment and timeline

    var feeStructureSelect = feeStructureSelectInput.value;
    var startDate = startDateInput.value;
    var estimatedEndDate = estimatedEndDateInput.value;
    var totalCost = totalCostInput.value;
    var paidUpfront = paidUpfrontInput.value;
    var endDate = endDateInput.value;
    var hourlyRate = hourlyRateInput.value;
    var maximumTotalHours = maximumTotalHoursInput.value;
    var estimatedHours = estimatedHoursInput.value;
    var frequency = frequencyInput.value;
    var ongoingCheckBox = ongoingCheckboxInput.checked;
    var monthlyRate = monthlyRateInput.value;
    var numberOfMonths = numberOfMonthsInput.value;
    var weeklyRate = weeklyRateInput.value;
    var numberOfWeeks = weeklyRateInput.value;
    if (
      projectName !== "" &&
      hiringManagerName !== "" &&
      companyName !== "" &&
      emailAddress !== "" &&
      service !== "" &&
      emailAddressInput.reportValidity()
    ) {
      step1.classList.add("is-done");
    } else {
      step1.classList.remove("is-done");
    }

    if (feeStructureSelect == "Flat Fee") {
      //flatrate condition
      if (
        startDate !== "" &&
        estimatedEndDate !== "" &&
        totalCost !== "" &&
        paidUpfront !== ""
      ) {
        step2.classList.add("is-done");
      } else {
        step2.classList.remove("is-done");
      }
    }

    if (feeStructureSelect == "Hourly Rate") {
      //hourly-rate condition
      if (
        startDate !== "" &&
        endDate !== "" &&
        hourlyRate !== "" &&
        maximumTotalHours !== ""
      ) {
        step2.classList.add("is-done");
      } else {
        step2.classList.remove("is-done");
      }
    }

    if (feeStructureSelect == "On Going Hourly") {
      //ongoing-hourly condition
      if (
        startDate !== "" &&
        endDate !== "" &&
        hourlyRate !== "" &&
        estimatedHours !== "" &&
        frequency !== "" &&
        ongoingCheckBox !== false
      ) {
        step2.classList.add("is-done");
      } else {
        step2.classList.remove("is-done");
      }
    }

    if (feeStructureSelect == "Monthly Recurring") {
      //monthly recurring condition
      if (startDate !== "" && monthlyRate !== "" && numberOfMonths !== "") {
        step2.classList.add("is-done");
      } else {
        step2.classList.remove("is-done");
      }
    }
    if (feeStructureSelect == "Weekly Recurring") {
      //weekly recurring condition
      if (startDate !== "" && weeklyRate !== "" && numberOfWeeks !== "") {
        step2.classList.add("is-done");
      } else {
        step2.classList.remove("is-done");
      }
    }

    // Project Scope

    var messageProjectScope = messageInput.value;
    if (messageProjectScope !== "") {
      step3.classList.add("is-done");
    } else {
      step3.classList.remove("is-done");
    }
  }
}

