reviewButton.addEventListener("click", function () {
  if (yourContract.checked) {
    yourContractDiv.style.display = "block";
    document.querySelector("[dx-success='contract']").style.display = "flex";
    document.querySelector("[dx-success='project']").style.display = "none";
  } else if (starterContract.checked) {
    starterContractDiv.style.display = "block";
    document.querySelector("[dx-success='contract']").style.display = "none";
    document.querySelector("[dx-success='project']").style.display = "flex";
  } else {}
  radioContractDiv.style.display = "none";
  buttonGroup.style.display = "flex";
  reviewButtonWrapper.style.display = "none";
  reviewForm();
  step5.classList.add("is-done");
});

editButton.addEventListener("click", function () {
  radioContractDiv.style.display = "block";
  starterContractDiv.style.display = "none";
  yourContractDiv.style.display = "none";
  buttonGroup.style.display = "none";
  reviewButtonWrapper.style.display = "flex";
  editForm();
  step5.classList.remove("is-done");
});

